106	                        <div class="repl-line">{ line }</div>
107	                    })}
108	                    <div class="repl-input-line">
109	                        <span class="repl-prompt">{ PROMPT }</span>
110	                        <span class="repl-input-text">{ &self.input }</span>
111	                        <span class={cursor_class}>{"\u{2588}"}</span>
112	                    </div>
113	                </div>
114	            </div>
